// utils/helpers.ts

import * as yup from 'yup';
import type {AnyObject, TestContext} from 'yup';
import type {IFormElement} from "@lmb-it/kitsconcerto-types";
import type {FieldValues} from "react-hook-form";

// --- General Utilities ---

/**
 * Safely retrieves a nested property from an object using a string path (e.g., "a.b[0].c").
 * This is useful for accessing nested form errors from react-hook-form's formState.
 *
 * @param {object} obj The object to query.
 * @param {string} path The string path to the desired property.
 * @returns {any} The value at the specified path, or undefined if not found.
 */
export const getPropertyByPath = (obj: Record<string, any>, path: string): any => {
    // This implementation is more robust than lodash.get and has no external dependencies.
    try {
        return path.split(/[.[\]]+/).filter(Boolean).reduce((res, key) => res[key], obj);
    } catch (e) {
        return undefined;
    }
};

/**
 * Checks if a given string is a valid, absolute URL.
 *
 * @param {string} urlString The string to validate.
 * @returns {boolean} True if the string is a valid URL.
 */
const isValidURL = (urlString: string): boolean => {

    try {
        // The URL constructor will throw an error for invalid URLs.
        const url = new URL(urlString);
        // Ensure it's a web protocol.
        return ['http:', 'https:'].includes(url.protocol);
    } catch (_) {
        return false;
    }
};


// --- Custom Validation Logic ---

interface FileValidationProps {
    min?: number;      // Minimum number of files
    max?: number;      // Maximum number of files
    minKB?: number;    // Minimum file size in kilobytes
    maxKB?: number;    // Maximum file size in kilobytes
}


/**
 * A custom Yup validation test for file and image uploads.
 *
 * Handles all output shapes produced by KitsFilePicker:
 *   - string URL              — existing server file (defaultValue / initialUri)
 *   - {base64, filename, type}  — JSON output (isJsonOutput=true, native & web)
 *   - {uri, name, type?, size?} — FormData output on native
 *   - DOM File instance         — FormData output on web
 */
export const formFileValidation = ({
                                   min,
                                   max,
                                   minKB,
                                   maxKB
                               }: FileValidationProps = {}): yup.MixedSchema<any, AnyObject, any> => {
    return yup.mixed().test('fileOrUrl', 'Invalid file or URL format', function (value: any) {
        const {path, createError} = this as TestContext;

        if (!value || (Array.isArray(value) && value.length === 0)) {
            return true; // Let a separate `.required()` handle empty values.
        }

        const files = Array.isArray(value) ? value : [value];

        // Validate file count
        if (min && files.length < min) {
            return createError({path, message: `Please upload at least ${min} file(s).`});
        }
        if (max && files.length > max) {
            return createError({path, message: `You can upload a maximum of ${max} file(s).`});
        }

        // Validate each item's shape and size
        const errorSizeFiles: string[] = [];

        for (const file of files) {
            // 1. URL string — already-saved server file; skip size check
            if (typeof file === 'string') {
                if (!isValidURL(file)) {
                    return createError({path, message: 'Items must be valid Files, URLs, or uploaded file objects.'});
                }
                continue;
            }

            if (typeof file !== 'object' || file === null) {
                return createError({path, message: 'Items must be valid Files, URLs, or uploaded file objects.'});
            }

            // 2. JSON output: { filename, base64, type } — native & web isJsonOutput=true
            if ('base64' in file) {
                if (typeof file.base64 !== 'string' || !file.base64) {
                    return createError({path, message: 'Items must be valid Files, URLs, or uploaded file objects.'});
                }
                if (minKB || maxKB) {
                    // Approximate decoded byte size: base64 encodes 3 bytes per 4 chars
                    const approxSizeKB = (file.base64.length * 3) / 4 / 1024;
                    const name = (file.filename || file.name || 'file') as string;
                    if ((maxKB && approxSizeKB > maxKB) || (minKB && approxSizeKB < minKB)) {
                        errorSizeFiles.push(name);
                    }
                }
                continue;
            }

            // 3. Native FormData output: { uri, name, type?, size? }
            if ('uri' in file) {
                if (typeof file.uri !== 'string' || !file.uri) {
                    return createError({path, message: 'Items must be valid Files, URLs, or uploaded file objects.'});
                }
                if ((minKB || maxKB) && file.size != null) {
                    const fileSizeKB = (file.size as number) / 1024;
                    const name = (file.name || 'file') as string;
                    if ((maxKB && fileSizeKB > maxKB) || (minKB && fileSizeKB < minKB)) {
                        errorSizeFiles.push(name);
                    }
                }
                continue;
            }

            // 4. Web DOM File object (FormData output on web)
            if (typeof File !== 'undefined' && file instanceof File) {
                const fileSizeKB = file.size / 1024;
                if ((maxKB && fileSizeKB > maxKB) || (minKB && fileSizeKB < minKB)) {
                    errorSizeFiles.push(file.name);
                }
                continue;
            }

            // Unknown shape — reject
            return createError({path, message: 'Items must be valid Files, URLs, or uploaded file objects.'});
        }

        if (errorSizeFiles.length > 0) {
            return createError({
                path,
                message: `Files (${errorSizeFiles.join(', ')}) are outside the size limitations.`
            });
        }

        return true;
    });
};

/**
 * Recursively checks for duplicate field IDs at each level of the element tree.
 * Throws an error if a duplicate is found.
 * @param fields The array of elements to check.
 */
export const checkNameDuplication = (fields: IFormElement<any>[]) => {
    const formNames: string[] = [];

    fields.forEach((item) => {
        const itemId = item.id as string;
        if (formNames.includes(itemId)) {
            throw new Error(`Field ID conflict: The ID "${itemId}" is duplicated. Field IDs must be unique within their nesting level.`);
        }
        if (!("displayOnly" in item) || !item.displayOnly) {
            formNames.push(itemId);
        }
        // Recursively check Group, Object, and Combined types.
        if ((item.type === "Group" || item.type === "Object" || item.type === "Combined") && 'elements' in item) {
            const elements = item.elements;
            if (typeof elements == 'function') {
                // checkNameDuplication(elements([], [], {} as ) as IFormElement<any>[]);

            } else {
                checkNameDuplication(elements);
            }
        }
    });
};


/**
 * Recursively builds the initial `defaultValues` object for react-hook-form.
 * @param fields The array of elements to process.
 * @returns An object with the form's default values.
 */
export const getDefaultValues = (fields: IFormElement<any>[]): Record<string, any> => {
    const defaultFormValues: FieldValues = {};

    // console.log({fields})
    fields.forEach((element) => {
        const elementId = element.id as string;
        if ("displayOnly" in element && element.displayOnly) return;

        // Handle Combined — register child defaults at top level and set parent initial value
        if (element.type === "Combined" && 'elements' in element) {
            const childElements = element.elements;
            if (Array.isArray(childElements)) {
                const childDefaults = getDefaultValues(childElements);
                Object.assign(defaultFormValues, childDefaults);
            }
            if ("initialValue" in element && element.initialValue !== undefined) {
                defaultFormValues[elementId] = element.initialValue;
            }
            return;
        }

        // Handle nested structures first
        if ((element.type === "Group" || element.type === "Object") && 'elements' in element) {
            const elements = element.elements;
            if (typeof elements == 'function') {
                // checkNameDuplication(elements([], [], {} as ) as IFormElement<any>[]);

            } else {
                defaultFormValues[elementId] = getDefaultValues(elements);
            }
            // For Groups: use initialValue (array of row objects) if provided,
            // otherwise default to empty array so useFieldArray starts with 0 rows.
            if (element.type === "Group") {
                if ("initialValue" in element && Array.isArray(element.initialValue) && element.initialValue.length > 0) {
                    defaultFormValues[elementId] = element.initialValue;
                } else {
                    defaultFormValues[elementId] = [];
                }
            }
            return;
        }

        // Handle specific types with special initial value logic
        if (element.type === "File" || element.type === "Image") {
            const initialUri = (element as any).initialUri;
            const limit = (element as any).multiple ? ((element as any).limit ?? 1) : 1;
            if (Array.isArray(initialUri)) {
                const filtered = initialUri.slice(0, limit).filter(isValidURL);
                if (filtered.length > 0) {
                    defaultFormValues[elementId] = filtered;
                }
            } else if (isValidURL(initialUri as string)) {
                defaultFormValues[elementId] = [initialUri];
            }
            return;
        }

        if (element.type === "Tags" && element.initialValue === undefined) {
            if ((element as any).isMultiple) {
                defaultFormValues[elementId] = [];
            }
            return;
        }

        // Handle standard initialValue
        if ("initialValue" in element && element.initialValue !== undefined) {
            defaultFormValues[elementId] = element.initialValue;
        }
    });

    return defaultFormValues;
};


/**
 * Recursively collects the IDs of all child elements inside Combined elements.
 * These IDs are internal to the Combined and should not appear in the form's output data.
 */
export const getCombinedChildIds = (fields: IFormElement<any>[]): Set<string> => {
    const childIds = new Set<string>();

    fields.forEach((element) => {
        if (element.type === "Combined" && 'elements' in element) {
            const children = element.elements;
            if (Array.isArray(children)) {
                children.forEach(child => childIds.add(child.id as string));
            }
        }
        // Recurse into Group/Object to find nested Combined elements
        if ((element.type === "Group" || element.type === "Object") && 'elements' in element) {
            const nested = element.elements;
            if (typeof nested !== 'function') {
                const nestedIds = getCombinedChildIds(nested);
                nestedIds.forEach(id => childIds.add(id));
            }
        }
    });

    return childIds;
};
